import React, { useEffect, useState } from "react";
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { CButton } from "@coreui/react";
import { customStyles } from "../../../utils/tableCustomStyles";
import { tableRemarksConstant } from "./tableRemarksConstant";
import DataTable from "react-data-table-component";
import ExportCSV from "../../../utils/ExportCsvButton";
import authService from "src/auth/auth.service";
import GetBusinessDetails from "src/components/services/GetBusinessDetails";
import alertPopUp from 'sweetalert2';
import withReactContent from 'sweetalert2-react-content';
import { deleteModalSwal } from "src/utils/Common";
import GoBackComponent from "src/utils/GoBackComponent";

const MySwal = withReactContent(alertPopUp);

const headers = [
    { label: "Department", key: "name" },
    { label: "Status", key: "status" },
    { label: "Created By", key: "createdBy" }
];

function RemarksList() {
    let location = useLocation();
    let navigate = useNavigate();
    const [rowData, setRowData] = useState([]);
    const [perPage, setPerPage] = useState(10);
    const [loading, setLoading] = useState(false);
    const [totalRows, setTotalRows] = useState(0);

    const fetchRemarksList = async (page, size) => {
        let data = {
            businessQueryId: location?.state?.businessQueryId,
            page: page || 1,
            size: size
        };
        if(location?.state?.type) {
            data.type = location?.state?.type
        }
        const response = await GetBusinessDetails.getAllRemarksList(data);
        if (response?.code === 200) {
            setRowData(response?.results?.content);
            setLoading(false);
            setTotalRows(response?.results?.totalElements);
        }
    }

    const handlePageChange = page => {
        fetchRemarksList(page, perPage);
    };

    const handlePerRowsChange = async (newPerPage, page) => {
        setPerPage(newPerPage);
        fetchRemarksList(page, newPerPage);
    };

    const handleDelete = async (id) => {
        let response = await GetBusinessDetails.deleteBusinessRemarks(id);
        if (response?.code === 200) {
            fetchRemarksList(0, 10);
        }
    }

    const handleConfirmModal = (id) => {
        const handleConfirm = async () => {
            const swalval = await MySwal.fire(deleteModalSwal);
            if (swalval && swalval.value === true) {
                handleDelete(id)
            }
        };
        handleConfirm();
    };

    useEffect(() => {
        console.log(location);
        if (location?.state?.businessQueryId) {
            fetchRemarksList(0, 10);
        } else {
            navigate("/business");
        }
    }, []);

    return (
        <div className='row'>
            <GoBackComponent goBackData={location?.state?.type === "PAGE_QUERY" ? "user-view-query" : "business"} />
            <div className="col2Large">
                <DataTable
                    title={`${location?.state?.type === "PAGE_QUERY" ? "Page" : "Business"} Query Remarks`}
                    columns={tableRemarksConstant(location?.state?.businessQueryStatus, location?.state?.type)}
                    data={rowData}
                    customStyles={customStyles}
                    //actions={actionButton()}
                    pagination
                    paginationPerPage={perPage}
                    pointerOnHover
                    fixedHeader
                    noContextMenu
                    fixedHeaderScrollHeight={"calc(100vh - 226px)"}
                    progressPending={loading}
                    paginationServer
                    paginationTotalRows={totalRows}
                    onChangeRowsPerPage={handlePerRowsChange}
                    onChangePage={handlePageChange}
                />
            </div>
            {authService.getPermission("REMARKS_CREATE") && <div className='col-sm-12'>
                <Link to={"/business/remarks/create"} state={{"businessQueryId": location?.state?.businessQueryId, type: location?.state?.type}}>
                    <CButton type="submit" color="primary" className="create-btn" style={{ float: "right" }}>
                        {"+ Create Remarks"}
                    </CButton>
                </Link>
            </div>}
        </div>
    );
}

export default RemarksList;
